/**
 * Sort order for Timeline items.
 * @public
 * @since 2.22.0
 */
declare enum TimelineSortOrder {
    /**
     * Ascending order (oldest first).
     * @public
     */
    Ascending = "Ascending",
    /**
     * Descending order (newest first).
     * @public
     */
    Descending = "Descending"
}
export default TimelineSortOrder;
